const items = $input.all();

return items.map(item => {
  const f = item.json.fields || item.json;
  const summary = f.Summary || '';
  const details = f.Details || '';
  const source = f.Source || 'Manual';
  const project = f.Project || 'Ops';
  const type = f.Type || 'Insight';
  const importance = parseInt(f.Importance) || 3;
  const tags = f.Tags ? (typeof f.Tags === 'string' ? f.Tags.split(',').map(t => t.trim()) : f.Tags) : [];
  const date = f.Date || null;

  if (!summary || summary.length < 3) return null;

  return {
    json: {
      summary,
      details,
      source,
      project,
      type,
      importance,
      tags,
      created_at: date,
      embeddingInput: summary + ' ' + details
    }
  };
}).filter(Boolean);

const items = $input.all();
const normalized = $('Normalize Records').all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const embedding = items[i].json.data[0].embedding;
  const prev = normalized[i]?.json || {};

  const body = JSON.stringify({
    summary: prev.summary,
    details: prev.details,
    source: prev.source,
    project: prev.project,
    type: prev.type,
    importance: prev.importance,
    tags: prev.tags,
    embedding: embedding,
    created_at: prev.created_at || new Date().toISOString(),
    expired: false
  });

  results.push({ json: { insertBody: body } });
}

return results;

const items = $input.all();
const success = items.filter(i => !i.json?.error).length;
const failed = items.filter(i => i.json?.error).length;
return [{ json: { total: items.length, success, failed, message: `Migration complete: ${success} inserted, ${failed} failed` } }];
